requests.testScript:
// ── 1. HTTP status ───────────────────────────────────────────────────────────
pw.test("Status 200", () => {
  pw.expect(pw.response.status).toBe(200);
});

// ── 2. Top-level shape ───────────────────────────────────────────────────────
pw.test("Response has required fields", () => {
  const b = pw.response.body;
  pw.expect(b).toHaveProperty("stock_code");
  pw.expect(b).toHaveProperty("exchange_code");
  pw.expect(b).toHaveProperty("ltp");
});

// ── 3. LTP sanity ────────────────────────────────────────────────────────────
pw.test("LTP is a positive number", () => {
  const ltp = pw.response.body.ltp;
  pw.expect(typeof ltp).toBe("number");
  pw.expect(ltp).toBeGreaterThan(0);
});

// ── 4. OHLC sanity ───────────────────────────────────────────────────────────
pw.test("High >= Low (when both present)", () => {
  const { high, low } = pw.response.body;
  if (high !== null && low !== null) {
    pw.expect(typeof high).toBe("number");
    pw.expect(typeof low).toBe("number");
    pw.expect(high).toBeGreaterThanOrEqual(low);
  }
});

pw.test("Open is a positive number (when present)", () => {
  const { open } = pw.response.body;
  if (open !== null) {
    pw.expect(typeof open).toBe("number");
    pw.expect(open).toBeGreaterThan(0);
  }
});

// ── 5. Echo-back check ───────────────────────────────────────────────────────
pw.test("stock_code echoed correctly", () => {
  const requested = JSON.parse(pw.request.body).stock_code;
  pw.expect(pw.response.body.stock_code).toBe(requested);
});

pw.test("exchange_code echoed correctly", () => {
  pw.expect(pw.response.body.exchange_code).toBe("NSE");
});

