pw.test("High >= Low (when both present)", () => {
  const { high, low } = pw.response.body;
  if (high !== null && low !== null) {
    pw.expect(typeof high).toBe("number");
    pw.expect(typeof low).toBe("number");
    pw.expect(high).toBeGreaterThanOrEqual(low);
  }
});

pw.test("Open is a positive number (when present)", () => {
  const { open } = pw.response.body;
  if (open !== null) {
    pw.expect(typeof open).toBe("number");
    pw.expect(open).toBeGreaterThan(0);
  }
});

